    cleaner.normalize_minmax(['feature1', 'feature2', 'feature3'])
    
    cleaned_df = cleaner.get_cleaned_data()
    print("Cleaned shape:", cleaned_df.shape)
    
    summary = cleaner.get_summary()
    for key, value in summary.items():
        print(f"{key}: {value}")
    
